#include <stdio.h>

int linearSearch(int arr[], int n, int target) {
    for (int i = 0; i < n; i++) {
        if (arr[i] == target) return i;
    }
    return -1;
}

int main() {
    int a[] = {1, 2, 3};
    if (linearSearch(a, 3, 99) == -1) printf("Not Found\n");
    return 0;
}
